## WSL-Specific Issues

**Display server differences:**
WSLg uses Weston as the Wayland compositor, which may behave differently from GNOME or KDE:

```csharp
public class DisplayServerDetector
{
    public static bool IsRunningInWSL()
    {
        try
        {
            var version = File.ReadAllText("/proc/version");
            return version.Contains("microsoft", StringComparison.OrdinalIgnoreCase);
        }
        catch
        {
            return false;
        }
    }

    public static void LogEnvironment()
    {
        Console.WriteLine($"WSL: {IsRunningInWSL()}");
        Console.WriteLine($"DISPLAY: {Environment.GetEnvironmentVariable("DISPLAY")}");
        Console.WriteLine($"WAYLAND_DISPLAY: {Environment.GetEnvironmentVariable("WAYLAND_DISPLAY")}");
        Console.WriteLine($"XDG_SESSION_TYPE: {Environment.GetEnvironmentVariable("XDG_SESSION_TYPE")}");
    }
}
```

**Font rendering:**
WSL may have limited font fallback support. Test with emoji and CJK characters:

```csharp
[Fact]
public void SkiaLabel_ComplexText_RendersCorrectly()
{
    var label = new SkiaLabel
    {
        Text = "Hello 世界 🌍 مرحبا"
    };

    var surface = CreateTestSurface(400, 100);
    label.Measure(new Size(400, 100));
    label.Arrange(new Rect(0, 0, 400, 100));
    label.Draw(surface.Canvas);

    // Verify text was rendered (not just boxes)
    var bitmap = surface.PeekPixels();
    Assert.True(HasNonWhitePixels(bitmap));
}
```

**Hardware acceleration:**
WSLg provides limited GPU access. Detect and fallback gracefully:

```csharp
public class RenderEngineFactory
{
    public static ISkiaRenderingEngine Create(IWindow window)
    {
        if (DisplayServerDetector.IsRunningInWSL())
        {
            // WSL: Prefer software rendering
            Console.WriteLine("WSL detected, using software rendering");
            return new SkiaRenderingEngine(window);
        }

        // Native Linux: Try GPU first
        try
        {
            var gpuEngine = new GpuRenderingEngine(window);
            if (gpuEngine.Initialize())
            {
                Console.WriteLine("Using GPU-accelerated rendering");
                return gpuEngine;
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"GPU initialization failed: {ex.Message}");
        }

        Console.WriteLine("Falling back to software rendering");
        return new SkiaRenderingEngine(window);
    }
}
```

## Native Linux Debugging

Testing in WSL provides convenience during development, but native Linux testing is essential for catching display server quirks, font rendering issues, and hardware acceleration problems.

**SSH remote debugging:**
```bash
# On Linux machine, install SSH server
sudo apt-get install openssh-server
sudo systemctl start ssh

# From Windows, connect via VS Code Remote-SSH
# Or use dotnet trace for profiling
ssh user@linux-machine
dotnet trace collect --process-id $(pgrep OpenMauiApp)
```

**Remote debugging with lldb:**
```bash
# Install lldb
sudo apt-get install lldb

# Attach to running process
sudo lldb -p $(pgrep OpenMauiApp)

# Set breakpoint
(lldb) breakpoint set --name SkiaButton.OnDraw
(lldb) continue
```

## Logging and Diagnostics

Implement comprehensive logging for debugging:

```csharp
public static class DiagnosticLogger
{
    private static readonly string LogPath = Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
        "OpenMauiApp",
        "logs",
        $"app-{DateTime.Now:yyyyMMdd-HHmmss}.log"
    );

    static DiagnosticLogger()
    {
        Directory.CreateDirectory(Path.GetDirectoryName(LogPath));
    }

    public static void LogEnvironment()
    {
        var sb = new StringBuilder();
        sb.AppendLine("=== Environment Information ===");
        sb.AppendLine($"OS: {Environment.OSVersion}");
        sb.AppendLine($"Runtime: {RuntimeInformation.FrameworkDescription}");
        sb.AppendLine($"WSL: {DisplayServerDetector.IsRunningInWSL()}");
        sb.AppendLine($"Display: {Environment.GetEnvironmentVariable("DISPLAY")}");
        sb.AppendLine($"Session Type: {Environment.GetEnvironmentVariable("XDG_SESSION_TYPE")}");
        sb.AppendLine($"Desktop: {Environment.GetEnvironmentVariable("XDG_CURRENT_DESKTOP")}");
        sb.AppendLine($"Theme: {Environment.GetEnvironmentVariable("GTK_THEME")}");

        File.AppendAllText(LogPath, sb.ToString());
    }

    public static void LogException(Exception ex, string context)
    {
        var sb = new StringBuilder();
        sb.AppendLine($"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] ERROR in {context}");
        sb.AppendLine($"Message: {ex.Message}");
        sb.AppendLine($"Stack Trace:\n{ex.StackTrace}");

        if (ex.InnerException != null)
        {
            sb.AppendLine($"Inner Exception: {ex.InnerException.Message}");
        }

        File.AppendAllText(LogPath, sb.ToString());
    }
}
```

## Performance Profiling

Compare performance between WSL and native Linux:

```csharp
public class PerformanceBenchmark
{
    [Benchmark]
    public void RenderComplexLayout()
    {
        var grid = CreateComplexGrid();
        var surface = CreateTestSurface(1920, 1080);

        var stopwatch = Stopwatch.StartNew();
